const input = $input.first().json;
const archivosCorregidos = input.corrected_files || [];
const itemsValidos = archivosCorregidos.filter(item => 
  (item.status === 'fixed' || item.status === 'verified') && 
  item.content && 
  item.content.trim() !== ''
);

const webhookData = $('Webhook').first().json.body;
const PROJECT_PATH = webhookData.project_path || '';
const OUTPUT_PATH = webhookData.output_path || "sobrescribir";

const resultados = [];
itemsValidos.forEach(item => {
  const fileName = item.file_name;
  const serviceName = $('Webhook').first().json.body.service;
  const composeFile = item.compose_file;
  const changes = item.changes || [];
  const carpeta = item.file_path || '';

  let rutaEscritura = '';
  if (OUTPUT_PATH !== "sobrescribir") {
    rutaEscritura = `${OUTPUT_PATH}\\${fileName}`;
  } else {
    rutaEscritura = `${carpeta}\\${fileName}`;
  }

  let rutaDestino = '';
  if (OUTPUT_PATH !== "sobrescribir") {
    rutaDestino = `${OUTPUT_PATH}`;
  } else {
    rutaDestino = `${carpeta}`;
  }

  const contentBase64 = Buffer.from(item.content, 'utf8').toString('base64');

  resultados.push({
    binary: {
      data: {
        data: contentBase64,
        fileName: fileName,
        mimeType: 'text/plain'
      }
    },
    json: {
      file_name: fileName,
      service_name: serviceName,
      project_path: PROJECT_PATH,
      ruta_escritura: rutaEscritura,
      ruta_completa: rutaDestino,
      carpeta_original: carpeta,
      compose_file: composeFile,
      cambios_realizados: changes,
      timestamp: new Date().toISOString(),
      output_path: OUTPUT_PATH
    }
  });
});
return resultados;

