const input = $input.first().json;

const rutaCompleta = input.ruta_completa;
const service = input.service || input.service_name || '';
const composeFile = input.compose_file || '';

if (!rutaCompleta || !service) {
    return [{ json: { ...input, comando: "" } }];
}

const comando = `cd /d "${rutaCompleta}" && docker compose -f ${composeFile} up -d ${service}`;

return [{ json: { ...input, comando } }];

