    ini: "config", conf: "config", cfg: "config", properties: "config",
    tf: "config", tfvars: "config", hcl: "config",

    // DATA
    sql: "data", db: "data", sqlite: "data", sqlite3: "data",
    csv: "data", tsv: "data", parquet: "data", jsonl: "data", ndjson: "data",
    log: "data", out: "data", err: "data",

    // DEPS
    "package.json": "deps", "package-lock.json": "deps", "yarn.lock": "deps",
    "pnpm-lock.yaml": "deps", "requirements.txt": "deps", "pipfile": "deps",
    "pipfile.lock": "deps", "pyproject.toml": "deps", "poetry.lock": "deps",
    "go.mod": "deps", "go.sum": "deps", "cargo.toml": "deps", "cargo.lock": "deps",
    "gemfile": "deps", "gemfile.lock": "deps", "composer.json": "deps",
    "composer.lock": "deps", "pubspec.yaml": "deps",

    // ENV
    env: "env",

    // DOCKER
    html: "docker", css: "docker", scss: "docker", md: "docker",
    pdf: "docker", jpg: "docker", png: "docker", svg: "docker", gif: "docker",
    ico: "docker", webp: "docker", mp4: "docker", mp3: "docker"
};

const nombresEspeciales = {
    "dockerfile": "docker",
};

let fileType = "code";
const nombreLower = fileName.toLowerCase();

if (nombresEspeciales[nombreLower]) {
    fileType = nombresEspeciales[nombreLower];
} else if (nombreLower.startsWith(".env")) {
    fileType = "env";
} else if (clasificacion[fileExtension]) {
    fileType = clasificacion[fileExtension];
}

return [{
    json: {
        file_name: fileName,
        service_name: serviceName,
        file_path: filePath,
        file_content: fileContent,
        compose_file: composeFile,
        mode: mode,
        file_type: fileType,
